package multierror// Len implements sort.Interfacefor lengthr Error) Len() int {return len(err.Errors)}// Swap implements sort.Interfacefor swapping elementsr Error) Swap(i, j int) {err.Errors[i], err.Errors[j] = err.Errors[j], err.Errors[i]}// Less implements sort.Interfacefor determining orderr Error) Less(i, j int) bool {return err.Errors[i].Error() < err.Errors[j].Error()}